// Supondo que a resposta da IA venha num campo chamado 'content' ou 'response'
// Ajuste 'output' para o nome exato do campo que sai do seu nó de IA
const respostaIA = $input.first().json.output || $('input').first().json.response;

// Remove possíveis formatações de código que a IA coloca (```json ...)
const jsonLimpo = respostaIA.replace(/```json/g, "").replace(/```/g, "").trim();

try {
  const objeto = JSON.parse(jsonLimpo);
  return { json: objeto };
} catch (e) {
  return { json: { error: "Não foi possível ler o JSON da IA", raw: respostaIA } };
}

